#include <stdio.h>
#include <stdlib.h>

// Structure for queue
typedef struct Node {
    int row;
    int col;
    int steps;
    struct Node* next;
} Node;

// Function to create a new node
Node* createNode(int row, int col, int steps) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->row = row;
    newNode->col = col;
    newNode->steps = steps;
    newNode->next = NULL;
    return newNode;
}

// Function to add a node to the queue
void enqueue(Node** queue, int row, int col, int steps) {
    Node* newNode = createNode(row, col, steps);
    if (*queue == NULL) {
        *queue = newNode;
    } else {
        Node* temp = *queue;
        while (temp->next != NULL) {
            temp = temp->next;
        }
        temp->next = newNode;
    }
}

// Function to remove a node from the queue
Node* dequeue(Node** queue) {
    Node* temp = *queue;
    *queue = (*queue)->next;
    return temp;
}

// Function to find the distance of the nearest 1 in the grid for each cell
void nearest(int** grid, int n, int m) {
    int** dist = (int**)malloc(n * sizeof(int*));
    for (int i = 0; i < n; i++) {
        dist[i] = (int*)malloc(m * sizeof(int));
    }

    Node* queue = NULL;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (grid[i][j] == 1) {
                enqueue(&queue, i, j, 0);
                dist[i][j] = 0;
            } else {
                dist[i][j] = -1;
            }
        }
    }

    int delRow[] = {-1, 0, 1, 0};
    int delCol[] = {0, 1, 0, -1};

    while (queue != NULL) {
        Node* temp = dequeue(&queue);
        int row = temp->row;
        int col = temp->col;
        int steps = temp->steps;

        for (int i = 0; i < 4; i++) {
            int nrow = row + delRow[i];
            int ncol = col + delCol[i];

            if (nrow >= 0 && nrow < n && ncol >= 0 && ncol < m && dist[nrow][ncol] == -1) {
                dist[nrow][ncol] = steps + 1;
                enqueue(&queue, nrow, ncol, steps + 1);
            }
        }

        free(temp);
    }

    // Print the distance matrix
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            printf("%d ", dist[i][j]);
        }
        printf("\n");
    }

    // Free the memory
    for (int i = 0; i < n; i++) {
        free(dist[i]);
    }
    free(dist);
}

int main() {
    int n, m;
    printf("Enter the number of rows and columns: ");
    scanf("%d %d", &n, &m);

    int** grid = (int**)malloc(n * sizeof(int*));
    for (int i = 0; i < n; i++) {
        grid[i] = (int*)malloc(m * sizeof(int));
    }

    printf("Enter the grid elements: \n");
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            scanf("%d", &grid[i][j]);
        }
    }

    nearest(grid, n, m);

    // Free the memory
    for (int i = 0; i < n; i++) {
        free(grid[i]);
    }
    free(grid);

    return 0;
}

